class Solution:
    def isTransformable(self, s: str, t: str) -> bool:
        if sorted(s) != sorted(t):
            return False
        remaining = list(s)
        for ch in t:
            idx = remaining.index(ch)
            for k in range(idx):
                if remaining[k] <= ch:
                    return False
            remaining.pop(idx)
        return True

