var isTransformable = function(s, t) {
    const sortedS = s.split('').sort().join('');
    const sortedT = t.split('').sort().join('');
    if (sortedS !== sortedT) return false;
    const pos = Array.from({ length: 10 }, () => []);
    for (let i = 0; i < s.length; i++) {
        pos[Number(s[i])].push(i);
    }
    const head = new Array(10).fill(0);
    for (let i = 0; i < t.length; i++) {
        const d = Number(t[i]);
        if (head[d] >= pos[d].length) return false;
        const p = pos[d][head[d]];
        for (let smaller = 0; smaller < d; smaller++) {
            if (head[smaller] < pos[smaller].length && pos[smaller][head[smaller]] < p) {
                return false;
            }
        }
        head[d]++;
    }
    return true;
};
